# exfil_detector.py
# Lightweight pattern detector for common exfiltration signals.

import re
from dataclasses import dataclass, field

# Patterns that appear in bulk-data dumps or exfiltration attempts
_BULK_PII_PATTERN = re.compile(
    r'(\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Z|a-z]{2,}\b.*?){5,}',
    re.DOTALL
)
_EXTERNAL_URL_IN_TOOL_CALL = re.compile(
    r'https?://(?!internal\.corp|localhost|127\.0\.0\.1)'
)

@dataclass
class ExfilSignal:
    rule_id: str
    severity: str  # critical | high | medium
    detail: str

@dataclass
class DetectionResult:
    signals: list[ExfilSignal] = field(default_factory=list)

    @property
    def is_clean(self) -> bool:
        return len(self.signals) == 0

    @property
    def max_severity(self) -> str:
        order = {"critical": 0, "high": 1, "medium": 2}
        if not self.signals:
            return "none"
        return min(self.signals, key=lambda s: order.get(s.severity, 99)).severity

def scan_output(text: str) -> DetectionResult:
    result = DetectionResult()
    if _BULK_PII_PATTERN.search(text):
        result.signals.append(ExfilSignal(
            rule_id="BULK_PII_001",
            severity="critical",
            detail="Five or more email addresses found in a single output block"
        ))
    return result

def scan_tool_call(tool_name: str, args: dict) -> DetectionResult:
    result = DetectionResult()
    # Flag any tool that sends data to an external URL
    for key, value in args.items():
        if isinstance(value, str) and _EXTERNAL_URL_IN_TOOL_CALL.search(value):
            result.signals.append(ExfilSignal(
                rule_id="EXTERNAL_POST_001",
                severity="critical",
                detail=f"Tool '{tool_name}' arg '{key}' contains external URL: {value[:80]}"
            ))
    return result
